from flask import Flask, redirect, request
import re

app = Flask(__name__)

@app.route('/shortlink')
def createShortLink():
    '''
    收取用戶嘅短連結請求，
    用正則表達式檢查係咪有效嘅網址格式，
    然後跳轉去預先設定好嘅官方網站
    '''
    allowed_domains = ['https://www.gov.hk', 'https://www.hkpl.gov.hk']
    target_url = request.args.get('url', '')

    if re.match(r'^https?://(?:[-\w\.]+)+[-\w]+(?:/[-\w\./?%&=]*)?$', target_url):
        for domain in allowed_domains:
            if target_url.startswith(domain):
                return redirect(target_url)

    return redirect('https://www.gov.hk')  # 安全預設跳轉

