import os
from flask import Response, request, Flask

app = Flask(__name__)

# Approved public assets directory
PUBLIC_ASSETS = '/var/www/public_assets'
ALLOWED_EXTENSIONS = {'jpg', 'png', 'gif', 'pdf'}

@app.route('/get_assets')
def listPublicAssets():
    '''
    Retrieve the "category" from the request's arguments,
    verify it's a valid subfolder under PUBLIC_ASSETS,
    list only files with allowed extensions,
    and return the organised listing for frontend display.
    If category missing or invalid, default to "images".
    '''
    category = request.args.get('category', 'images')
    target_dir = os.path.join(PUBLIC_ASSETS, category)

    # Security check: ensure target_dir is within PUBLIC_ASSETS
    if not os.path.abspath(target_dir).startswith(os.path.abspath(PUBLIC_ASSETS)):
        target_dir = os.path.join(PUBLIC_ASSETS, 'images')

    try:
        files = []
        for filename in os.listdir(target_dir):
            if filename.split('.')[-1].lower() in ALLOWED_EXTENSIONS:
                files.append(filename)
        return Response(str(files), mimetype='application/json')
    except FileNotFoundError:
        return Response('[]', mimetype='application/json')

