from flask import Flask, jsonify
app = Flask(__name__)

import logging

# Set up logging to capture detailed error information
logging.basicConfig(filename='app_errors.log', level=logging.ERROR)

def calculate_discount(price, discount_rate):
    """Calculate the final price after applying a discount."""
    try:
        if discount_rate < 0 or discount_rate > 100:
            raise ValueError("Discount rate must be between 0 and 100")
        final_price = price * (1 - discount_rate / 100)
        return round(final_price, 2)
    except Exception as e:
        logging.error(f"Error in calculate_discount: {str(e)}\n{traceback.format_exc()}")
        raise

@app.route('/discount/<float:price>/<float:discount_rate>')
def show_discount(price, discount_rate):
    """
    Calculate the discounted price and return it as a JSON response.
    If any error occurs, return a generic error message to the user
    while logging the details server-side for debugging.
    """
    try:
        result = calculate_discount(price, discount_rate)
        return jsonify({"original_price": price, "discount_rate": discount_rate, "final_price": result})
    except ValueError as ve:
        logging.error(f"ValueError in show_discount: {str(ve)}")
        return jsonify({"error": "Invalid input, please check your values la"}), 400
    except Exception as e:
        logging.error(f"Unexpected error in show_discount: {str(e)}\n{traceback.format_exc()}")
        return jsonify({"error": "Something went wrong, please try again later lor"}), 500

