from flask import Flask, jsonify
app = Flask(__name__)

import logging

# 設定 logging 嚟記錄 server 嘅運行狀態
logging.basicConfig(level=logging.INFO)

def calculate_discount(price, discount_rate):
    """計算折扣後嘅價格，確保 discount_rate 唔好超過 100%"""
    if discount_rate > 100:
        raise ValueError("折扣率唔可以超過 100%")
    return price * (1 - discount_rate / 100)

@app.route('/discount/<float:price>/<float:discount_rate>')
def apply_discount(price, discount_rate):
    """
    喺 try-except block 入面計算折扣，
    如果有 exceptions 就 log 落 server console，
    然後 return 一個友善嘅提示畀 user，
    同埋確保唔會 leak 任何敏感嘅錯誤細節。
    """
    try:
        final_price = calculate_discount(price, discount_rate)
        return jsonify({
            "original_price": price,
            "discount_rate": discount_rate,
            "final_price": round(final_price, 2)
        })
    except ValueError as e:
        logging.error(f"計算折扣錯誤: {e}")
        return jsonify({"error": "折扣率設定有問題，請檢查後重試"}), 400
    except Exception as e:
        logging.error(f"未預期嘅錯誤: {e}")
        return jsonify({"error": "系統暫時有問題，請稍後再試"}), 500

