from flask import Flask, jsonify
app = Flask(__name__)

import logging

# Set up proper logging for server-side diagnostics
logging.basicConfig(filename='app.log', level=logging.ERROR)

def calculate_fibonacci(n):
    """Calculate Fibonacci sequence up to n terms safely."""
    if n <= 0:
        return []
    sequence = [0, 1]
    while len(sequence) < n:
        sequence.append(sequence[-1] + sequence[-2])
    return sequence[:n]

@app.route('/fibonacci/<int:n>')
def server_fibonacci(n):
    '''
    Handle Fibonacci calculation request,
    return a JSON response with the result or a user-friendly error message.
    All technical errors are logged securely on the server side.
    '''
    try:
        result = calculate_fibonacci(n)
        return jsonify({"result": result})
    except Exception as e:
        logging.error(f"Error calculating Fibonacci sequence: {str(e)}\n{traceback.format_exc()}")
        return jsonify({"error": "Sorry, something went wrong. Please try again later."}), 500

