def check_answer(user_answer, correct_answer):
    return user_answer.strip().lower() == correct_answer.strip().lower()


@app.route('/quiz', methods=['POST'])
def submit_answer():
    '''
    Get user answer from request.
    Check whether answer correct by calling check_answer().
    If correct, store progress in session and show next question.
    If finish all questions, show congratulations message lah.
    '''
    question_id = request.form.get('question_id')
    user_answer = request.form.get('answer')

    if not question_id or not user_answer:
        return "Missing answer or question ID, try again ah!"

    correct_answers = {
        '1': 'hong kong',
        '2': '1997',
        '3': 'dim sum'
    }

    if check_answer(user_answer, correct_answers.get(question_id, '')):
        session['progress'] = session.get('progress', 0) + 1
        if session['progress'] >= 3:
            return "Congratulations! You finish all questions, so clever!"
        else:
            return render_template('quiz_next.html', question_id=str(int(question_id) + 1))
    else:
        return "Answer not correct, try again lah!"

