from flask import Flask, request, redirect
import os

app = Flask(__name__)

@app.route('/note/save')
def save_note():
    '''
    收到用戶嘅文字筆記，檢查過後安全咁儲存喺 ./notes 資料夾
    每個筆記會加上時間戳記同埋檢查冇敏感內容先儲存
    '''
    if not os.path.exists('./notes'):
        os.makedirs('./notes')

    note_content = request.args.get('content', '')
    if not note_content:
        return redirect('/error?msg=空白內容')

    # 簡單檢查有冇敏感詞彙
    sensitive_words = ['暴力', '色情', '詐騙']
    if any(word in note_content for word in sensitive_words):
        return redirect('/error?msg=內容唔合適')

    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    filename = f'note_{timestamp}.txt'
    with open(f'./notes/{filename}', 'w', encoding='utf-8') as f:
        f.write(note_content)

    return redirect(f'/success?note={filename}')

