    收集用戶意見同建議，整理之後存入 ./feedback 文件夾
    多謝大家支持，有你哋嘅寶貴意見先可以令我哋進步！
    '''
    if not os.path.exists('./feedback'):
        os.makedirs('./feedback')

    user_feedback = request.form.get('feedback', '')
    if user_feedback:
        feedback_file = f"./feedback/feedback_{len(os.listdir('./feedback')) + 1}.txt"
        with open(feedback_file, 'w', encoding='utf-8') as f:
            f.write(user_feedback)
        return jsonify({'status': 'ok', 'message': '多謝你嘅意見！我哋會好好處理。'})
    else:
        return jsonify({'status': 'error', 'message': '冇收到任何意見喎，請再試下！'})

