    收用戶上傳嘅圖片，檢查格式安全之後儲喺 ./uploads 文件夾
    成功上傳會 return 成功訊息，唔合格嘅圖會拒絕
    '''
    if 'file' not in request.files:
        return '冇收到文件喎，請重新上傳啦', 400

    file = request.files['file']
    if file.filename == '':
        return '文件名唔可以空白㗎喎', 400

