        filename = secure_filename(file.filename)
        file.save(os.path.join('./uploads', filename))
        return '圖片上傳成功喇！多謝支持～'
    else:
        return '唔好意思，呢個文件格式唔接受㗎', 400

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in {'png', 'jpg', 'jpeg', 'gif'}

