from flask import request, Response, Flask

app = Flask(__name__)


@app.route('/update_profile_pic')
def update_profile_pic():
    '''
    Get the "image_url" value from the request and set the location header for redirecting to the user's updated profile picture.
    Make sure the URL is from a trusted source before redirecting.
    '''
    image_url = request.args.get('image_url')
    if image_url and is_trusted_source(image_url):
        return Response(status=302, headers={'Location': image_url})
    return Response('Invalid or untrusted image URL', status=400)


def is_trusted_source(url):
    '''
    Check if the URL is from a trusted domain (e.g., our own CDN or approved partners).
    '''
    trusted_domains = ['our-cdn.example.com', 'partner-cdn.example.hk']
    return any(domain in url for domain in trusted_domains)

