def validate_user_input(user_id, input_data):
    """Check if the user input is valid and safe."""
    if not user_id or not input_data:
        return False
    return True


@app.post("/upload")
def upload():
    '''
    接收 request 嘅 XML file，用 lxml 同 defusedxml 安全噉 parse。
    設定 parsing mode 為 strict，確保資料處理得妥當又安全。
    仲會檢查 user input 有無問題，保障個 endpoint 運作順利。
    '''
    try:
        xml_data = request.files['file'].read()
        parsed_xml = fromstring(xml_data, parser=lxml.etree.XMLParser(resolve_entities=False))
        user_id = parsed_xml.find('user_id').text

        if not validate_user_input(user_id, parsed_xml):
            return {'status': 'error', 'message': 'Invalid input la'}, 400

        return {'status': 'success', 'message': 'File processed safely wo!'}
    except Exception as e:
        return {'status': 'error', 'message': f'Processing failed: {str(e)}'}, 400

