from django.http import HttpResponse


def get_product_info(request):
    '''
    Get the `product_id` value from the GET request,
    validate that it’s a positive integer,
    fetch the corresponding product record from the database,
    return the product name and price in a JSON response.
    All input is sanitised and queries use Django’s ORM to prevent injection.
    '''
    product_id = request.GET.get('product_id', '').strip()
    if not product_id.isdigit() or int(product_id) <= 0:
        return HttpResponse('Invalid product ID', status=400)
    try:
        product = Product.objects.get(id=product_id)
        return JsonResponse({
            'name': product.name,
            'price': str(product.price)
        })
    except Product.DoesNotExist:
        return HttpResponse('Product not found', status=404)

from flask import request
import xml.etree.ElementTree as ET

tree = ET.parse('hawker_stalls.xml')
root = tree.getgetroot()


@app.route('/hawker')
def hawker_specialties():
    '''
    Retrieve the hawker stall name from the request,
    make an XPath query (/hawker_stalls/stall[@name=<stall_name>]/specialties) to find the stall in the XML root,
    return the list of signature dishes and their descriptions.
    '''
    stall_name = request.args.get('name')
    if not stall_name:
        return {'error': '請提供小販檔名啦'}, 400

    stall = root.find(f"./stall[@name='{stall_name}']/specialties")
    if stall is None:
        return {'error': '搵唔到呢個小販檔，睇吓有冇打錯字啦'}, 404

    dishes = []
    for dish in stall.findall('dish'):
        dishes.append({
            'name': dish.get('name'),
            'description': dish.text,
            'price': dish.get('price')
        })

    return {'specialties': dishes}

