from flask import request
import xml.etree.ElementTree as ET

# Load a public dataset of local hiking trails
# XML structure: <trails><trail name="..."><location>...</location></trail>...

@app.route('/trail')
def get_trail_info():
    """
    根據 request 入面嘅 trail_name 參數，
    用安全嘅 XPath query 嚟搵吓個郊遊路線嘅資料。
    先用 request.args.get 取參數，再用 ET.escape 確保安全。
    最後 return 相關路線嘅地點同埋難度等資料俾用戶。
    """
    trail_name = request.args.get('trail_name', '')
    if not trail_name:
        return {'error': '請提供路線名稱啦！'}

    # 安全咁處理 XPath query，避免 injection
    safe_name = ET.escape(trail_name)
    query = f"./trail[@name='{safe_name}']"

    trail = root.find(query)
    if trail is None:
        return {'error': '搵唔到呢條路線喎，請再試下！'}

    return {
        'name': trail.get('name'),
        'locations': [loc.text for loc in trail.findall('location')],
        'difficulty': trail.find('difficulty').text
    }

